mapper.select:
SELECT COUNT(*)
FROM ${tableName}
WHERE community_id = #{communityId}
  AND status = 'entered'

SELECT id, community_id, house_no, car_number, vehicle_type,
       enter_time, exit_time, duration, status,
       exception_reason, handler_admin_id, handle_time, handle_remark,
       create_time, update_time
FROM ${tableName}
WHERE community_id = #{communityId}
  AND car_number = #{carNumber}
  AND status = 'entered'
ORDER BY enter_time DESC
LIMIT 1

mapper.update:
UPDATE ${tableName}
SET status = #{record.status},
    exit_time = #{record.exitTime},
    duration = #{record.duration},
    update_time = NOW()
WHERE id = #{record.id}

mapper.select:
SELECT id, community_id, house_no, car_number, vehicle_type,
       enter_time, exit_time, duration, status,
       exception_reason, handler_admin_id, handle_time, handle_remark,
       create_time, update_time
FROM ${tableName}
WHERE id = #{id}
  AND community_id = #{communityId}
LIMIT 1

SELECT * FROM (

        SELECT id, community_id, house_no, car_number, vehicle_type,
               enter_time, exit_time, duration, status,
               exception_reason, handler_admin_id, handle_time, handle_remark,
               create_time, update_time
        FROM ${tbl}
        WHERE community_id = #{communityId}
          AND house_no = #{houseNo}
          AND enter_time >= #{startTime}
          AND enter_time <= #{endTime}

          AND (enter_time < #{cursorTime}
               OR (enter_time = #{cursorTime} AND id < #{cursorId}))


) AS combined
ORDER BY enter_time DESC, id DESC
LIMIT #{limit}
